private func handleStaleHeartbeat() {
    guard let data = try? Data(contentsOf: heartbeatFileURL),
          let timeStr = String(data: data, encoding: .utf8),
          let lastHeartbeatTime = TimeInterval(timeStr) else {
        return
    }
    let lastHeartbeat = Date(timeIntervalSince1970: lastHeartbeatTime)

    let threshold = AppDelegate.heartbeatStaleThreshold
    let age = Date().timeIntervalSince(lastHeartbeat)

    guard age > threshold else { return }

    recordScreenEvent(.off, at: lastHeartbeat)
    recordScreenEvent(.on)
}

func recordScreenEvent(_ kind: ScreenEvent.Kind, at time: Date = Date()) {
    var data = loadData()
    let todayEvents = data.screenEvents.filter { Calendar.current.isDateInToday($0.time) }
    if let last = todayEvents.last, last.kind == kind { return }
    data.screenEvents.append(ScreenEvent(kind: kind, time: time))
    saveData(data)
    eventLog.append(at: time, eventType: kind.rawValue, eventSource: "computer", projectName: "-")
}

